INSERT INTO `paragrafo` VALUES (97180,1,'O Índice de Massa Corporal (IMC) é um parâmetro bastante utilizado para classificar o indivíduo de acordo com seu peso e altura. Seu uso é disseminado principalmente entre profissionais que trabalham com o corpo, como médicos, fisioterapeutas e profissionais de Educação Física. É importante ressaltar que a Organização Mundial da Saúde (OMS) utiliza esse índice como indicador do nível de obesidade nos diferentes países. O * cálculo desse índice é bastante simples e, para utilizá-lo, basta saber o seu peso (em kg) e a sua altura (em metros) e inseri-los na fórmula. A fórmula para o cálculo do IMC, bem como a tabela para classificação encontram-se a seguir:',NULL,97178);
